external_knowledge:
Running low in stock refers to items whose current quantity meets or falls below their pre-set reorder level, indicating a need for restocking to maintain inventory levels. ;
Contact details are essential for communicating the need for restocking to suppliers or managers. ;
Owners could be suppliers, manufacturers, or other entities responsible for providing the items. ;
Item identifiers and names help in specifying which exact items are running low and need attention. ;

sql:
SELECT item_id, name, cost
FROM items
WHERE cost > (SELECT AVG(cost) FROM items);

SELECT name, cost, quantity, reorder_level
FROM items
WHERE quantity < reorder_level;

SELECT name
FROM items
WHERE IFNULL(cost, 0) > (SELECT AVG(IFNULL(cost, 0)) FROM items);

SELECT items.name AS 'Item Name', owners.owner_name AS 'Owner Name'
FROM items
LEFT JOIN owners ON items.owner_id = owners.owner_id;

SELECT i.name AS 'Item Name', o.owner_name AS 'Owner Name'
FROM items i
INNER JOIN owners o ON i.owner_id = o.owner_id;

SELECT item_id, name, cost
FROM items
WHERE cost > (SELECT AVG(cost) FROM items);
